package com.finance.tracker.dashboard;
import com.finance.tracker.security.UserPrincipal; import com.finance.tracker.transaction.*; import java.math.*; import java.time.*; import java.util.*; import org.springframework.security.core.annotation.AuthenticationPrincipal; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/dashboard") public class DashboardController {private final TransactionRepository repo;public DashboardController(TransactionRepository repo){this.repo=repo;}@GetMapping("/summary") public Summary summary(@AuthenticationPrincipal UserPrincipal u){LocalDate now=LocalDate.now(),start=now.withDayOfMonth(1),end=start.withDayOfMonth(start.lengthOfMonth());BigDecimal income=repo.sumByUserAndTypeAndDates(u.id(),TransactionType.INCOME,start,end),expense=repo.sumByUserAndTypeAndDates(u.id(),TransactionType.EXPENSE,start,end);Map<String,BigDecimal> cats=new LinkedHashMap<>();repo.expenseByCategory(u.id(),start,end).forEach(x->cats.put((String)x[0],(BigDecimal)x[1]));List<MonthlyTotal> months=new ArrayList<>();for(int i=5;i>=0;i--){LocalDate s=now.withDayOfMonth(1).minusMonths(i),e=s.withDayOfMonth(s.lengthOfMonth());months.add(new MonthlyTotal(s.getMonth().toString().substring(0,3),repo.sumByUserAndTypeAndDates(u.id(),TransactionType.INCOME,s,e),repo.sumByUserAndTypeAndDates(u.id(),TransactionType.EXPENSE,s,e)));}return new Summary(income,expense,income.subtract(expense),cats,months);}
 public record Summary(BigDecimal monthlyIncome,BigDecimal monthlyExpense,BigDecimal monthlyBalance,Map<String,BigDecimal> expensesByCategory,List<MonthlyTotal> lastSixMonths){}public record MonthlyTotal(String label,BigDecimal income,BigDecimal expense){}
}
